            messages.success(
                request,
                f'Account created for {employee.get_full_name()} ({employee.employee_id}).'
            )
            return redirect('accounts:employee_list')
    else:
        form = EmployeeCreationForm()

    return render(request, 'accounts/create_employee.html', {'form': form})

